const fs = require('fs');
const path = require('path');

const srcDir = path.join(__dirname, 'frontend', 'dist', 'assets');
const outPath = path.join(__dirname, 'src', 'include', 'web_assets.hpp');

const files = fs.readdirSync(srcDir);

let outContent = `// Auto-generated by bundle.js
#pragma once
#include <cstdint>
#include <cstddef>
#include <string>
#include <unordered_map>

namespace duckdb {
namespace web_assets {

struct Asset {
    const uint8_t* data;
    size_t size;
    const char* content_type;
};

`;

const htmlContent = fs.readFileSync(path.join(__dirname, 'frontend', 'dist', 'index.html'));

function bufferToHex(buffer) {
    let hexParts = [];
    for (let i = 0; i < buffer.length; i++) {
        hexParts.push('0x' + buffer[i].toString(16).padStart(2, '0'));
    }
    return hexParts.join(', ');
}

outContent += `const uint8_t index_html[] = { ${bufferToHex(htmlContent)} };\n`;
outContent += `const size_t index_html_len = sizeof(index_html);\n\n`;

let mapEntries = ['    {"/index.html", { index_html, index_html_len, "text/html" }}'];


for (const file of files) {
    const filePath = path.join(srcDir, file);
    const content = fs.readFileSync(filePath);
    
    // Create safe C++ variable name
    let varName = file.replace(/[^a-zA-Z0-9]/g, '_');
    
    outContent += `const uint8_t asset_${varName}[] = { ${bufferToHex(content)} };\n`;
    outContent += `const size_t asset_${varName}_len = sizeof(asset_${varName});\n\n`;
    
    let mime = 'application/octet-stream';
    if (file.endsWith('.js')) mime = 'application/javascript';
    else if (file.endsWith('.css')) mime = 'text/css';
    
    mapEntries.push(`    {"/assets/${file}", { asset_${varName}, asset_${varName}_len, "${mime}" }}`);
}

outContent += `
inline const std::unordered_map<std::string, Asset>& get_assets() {
    static const std::unordered_map<std::string, Asset> assets = {
${mapEntries.join(',\n')}
    };
    return assets;
}

} // namespace web_assets
} // namespace duckdb
`;

fs.writeFileSync(outPath, outContent);
console.log('Successfully wrote web_assets.hpp');
